625: 	if config == nil {
626: 		return
627: 	}
628: 	if config.SecurityDefinitions != nil {
629: 		// Setup OpenAPI security: all APIs will have the same authentication for now.
630: 		config.DefaultSecurity = []map[string][]string{}
631: 		keys := []string{}
632: 		for k := range *config.SecurityDefinitions {
633: 			keys = append(keys, k)
634: 		}
635: 		sort.Strings(keys)
636: 		for _, k := range keys {
