643: 			config.CommonResponses[http.StatusUnauthorized] = spec.Response{
644: 				ResponseProps: spec.ResponseProps{
645: 					Description: "Unauthorized",
646: 				},
647: 			}
648: 		}
649: 	}
650: 	// make sure we populate info, and info.version, if not manually set
651: 	if config.Info == nil {
652: 		config.Info = &spec.Info{}
653: 	}
654: 	if config.Info.Version == "" {
655: 		if version != nil {
656: 			config.Info.Version = strings.Split(version.String(), "-")[0]
