712: // Complete fills in any fields not set that are required to have valid data and can be derived
713: // from other fields. If you're going to `ApplyOptions`, do that first. It's mutating the receiver.
714: func (c *Config) Complete(informers informers.SharedInformerFactory) CompletedConfig {
715: 	if c.FeatureGate == nil {
716: 		c.FeatureGate = utilfeature.DefaultFeatureGate
717: 	}
718: 	if len(c.ExternalAddress) == 0 && c.PublicAddress != nil {
719: 		c.ExternalAddress = c.PublicAddress.String()
720: 	}
721: 
722: 	// if there is no port, and we listen on one securely, use that one
723: 	if _, _, err := net.SplitHostPort(c.ExternalAddress); err != nil {
724: 		if c.SecureServing == nil {
725: 			klog.Fatalf("cannot derive external address port without listening on a secure port.")
726: 		}
727: 		_, port, err := c.SecureServing.HostPort()
728: 		if err != nil {
729: 			klog.Fatalf("cannot derive external address from the secure port: %v", err)
730: 		}
731: 		c.ExternalAddress = net.JoinHostPort(c.ExternalAddress, strconv.Itoa(port))
732: 	}
733: 	completeOpenAPI(c.OpenAPIConfig, c.EffectiveVersion.EmulationVersion())
734: 	completeOpenAPIV3(c.OpenAPIV3Config, c.EffectiveVersion.EmulationVersion())
735: 
736: 	if c.DiscoveryAddresses == nil {
737: 		c.DiscoveryAddresses = discovery.DefaultAddresses{DefaultAddress: c.ExternalAddress}
738: 	}
739: 
740: 	AuthorizeClientBearerToken(c.LoopbackClientConfig, &c.Authentication, &c.Authorization)
741: 
742: 	if c.RequestInfoResolver == nil {
743: 		c.RequestInfoResolver = NewRequestInfoResolver(c)
744: 	}
745: 
746: 	if c.EquivalentResourceRegistry == nil {
747: 		if c.RESTOptionsGetter == nil {
748: 			c.EquivalentResourceRegistry = runtime.NewEquivalentResourceRegistry()
749: 		} else {
750: 			c.EquivalentResourceRegistry = runtime.NewEquivalentResourceRegistryWithIdentity(func(groupResource schema.GroupResource) string {
751: 				// use the storage prefix as the key if possible
752: 				if opts, err := c.RESTOptionsGetter.GetRESTOptions(groupResource, nil); err == nil {
753: 					return opts.ResourcePrefix
754: 				}
755: 				// otherwise return "" to use the default key (parent GV name)
756: 				return ""
757: 			})
758: 		}
759: 	}
760: 
761: 	return CompletedConfig{&completedConfig{c, informers}}
762: }
